import React from 'react';

// White key dimensions and positions
// Each white key is 64px wide — 7 keys = 448px total keyboard width
const W = 64;
const WHITE_KEY_HEIGHT = 160;
const WHITE_KEYS = ['C', 'D', 'E', 'F', 'G', 'A', 'B'];

// Black key dimensions
// Positioned at 70% into the white key they sit on (standard piano proportions)
const BW = 36;
const BLACK_KEY_HEIGHT = 100;
const BLACK_KEYS = [
  { note: 'C#', x: W * 0.7 },          // sits between C and D
  { note: 'D#', x: W * 1.7 },          // sits between D and E
  { note: 'F#', x: W * 3.7 },          // sits between F and G (no black key between E and F)
  { note: 'G#', x: W * 4.7 },          // sits between G and A
  { note: 'A#', x: W * 5.7 },          // sits between A and B
];

// highlightedNotes: array of note strings to colour green (e.g. ['C','E','G'])
// onKeyClick: called with the note name when a key is clicked
export const PianoKeyboard = ({ onKeyClick, highlightedNotes = [] }) => {
  const isHighlighted = (note) => highlightedNotes.includes(note);

  return (
    <svg
      width={W * 7}
      height={WHITE_KEY_HEIGHT + 2}
      viewBox={`0 0 ${W * 7} ${WHITE_KEY_HEIGHT + 2}`}
      className="drop-shadow-2xl"
    >
      {/* White keys — rendered first so black keys appear on top */}
      {WHITE_KEYS.map((note, i) => (
        <g key={note} onClick={() => onKeyClick(note)} className="cursor-pointer">
          <rect
            x={i * W + 1}
            y={1}
            width={W - 2}
            height={WHITE_KEY_HEIGHT}
            rx={4}
            fill={isHighlighted(note) ? '#1db954' : 'white'}
            stroke="#222"
            strokeWidth={1}
            className="transition-all duration-150 hover:opacity-80"
          />
          {/* Note label at the bottom of each white key */}
          <text
            x={i * W + W / 2}
            y={WHITE_KEY_HEIGHT - 10}
            textAnchor="middle"
            fontSize="12"
            fontWeight="bold"
            fill={isHighlighted(note) ? '#000' : '#999'}
            className="pointer-events-none select-none"
          >
            {note}
          </text>
        </g>
      ))}

      {/* Black keys — rendered after white keys so they sit visually on top */}
      {BLACK_KEYS.map(({ note, x }) => (
        <g key={note} onClick={() => onKeyClick(note)} className="cursor-pointer">
          <rect
            x={x}
            y={1}
            width={BW}
            height={BLACK_KEY_HEIGHT}
            rx={3}
            fill={isHighlighted(note) ? '#1db954' : '#111'}
            stroke="#000"
            strokeWidth={1}
            className="transition-all duration-150 hover:opacity-70"
          />
        </g>
      ))}
    </svg>
  );
};
